export const 鎮宅蛇鼠 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿二＋W折圈鏈＋散圈
    線(p => p.M(X(1.0), Z(1.4)).L(X(6.5), Z(1.3)));
    圈(0.7, 1.4);
    圈(6.8, 1.3);
    線(p => p.M(X(1.0), Z(2.4)).L(X(6.5), Z(2.3)));
    圈(0.7, 2.4);
    圈(6.8, 2.3);
    const W = [[1.0, 3.6], [2.4, 4.4], [3.8, 3.5], [5.2, 4.3], [6.5, 3.4]];
    for (const p_ of W)
        圈(...p_);
    for (let i = 0; i < 4; i++)
        連(W[i], W[i + 1]);
    for (const [x, z] of [[1.2, 5.5], [2.8, 5.6], [4.4, 5.5], [6.0, 5.4]])
        圈(x, z);
    // 左目梯六箱
    線(p => p.M(X(0.9), Z(6.4)).L(X(0.9), Z(16.0)));
    線(p => p.M(X(3.3), Z(6.35)).L(X(3.3), Z(15.95)));
    for (let i = 0; i <= 6; i++)
        線(p => p.M(X(0.9), Z(6.4 + i * 1.6)).L(X(3.3), Z(6.35 + i * 1.6)));
    // 右柱：古罒皃字形疊承小梯（摹形從簡）
    線(p => p.M(X(4.2), Z(6.8)).L(X(6.2), Z(6.75)), 0.36);
    線(p => p.M(X(5.2), Z(6.5)).L(X(5.18), Z(7.6)), 0.34);
    線(p => p.M(X(4.5), Z(7.6)).L(X(4.5), Z(8.6)).L(X(5.9), Z(8.55))
        .L(X(5.9), Z(7.55)).L(X(4.45), Z(7.6)), 0.32);
    線(p => p.M(X(4.3), Z(9.2)).L(X(4.3), Z(10.4)).L(X(6.1), Z(10.35))
        .L(X(6.1), Z(9.15)).L(X(4.25), Z(9.2)));
    線(p => p.M(X(4.9), Z(9.25)).L(X(4.88), Z(10.35)), 0.3);
    線(p => p.M(X(5.5), Z(9.2)).L(X(5.48), Z(10.3)), 0.3);
    // 皃曲
    線(p => p.M(X(4.6), Z(10.9))
        .C(X(4.4), Z(11.5), X(4.6), Z(12.0), X(5.2), Z(12.05))
        .C(X(5.7), Z(12.1), X(5.9), Z(11.7), X(5.6), Z(11.45)), 0.36);
    // 小梯
    線(p => p.M(X(4.3), Z(12.7)).L(X(4.3), Z(16.0)));
    線(p => p.M(X(6.2), Z(12.65)).L(X(6.2), Z(15.95)));
    for (let i = 0; i <= 2; i++)
        線(p => p.M(X(4.3), Z(12.7 + i * 1.65)).L(X(6.2), Z(12.65 + i * 1.65)));
    // 底皃曲
    線(p => p.M(X(1.6), Z(16.6))
        .C(X(1.4), Z(17.3), X(1.6), Z(17.9), X(2.3), Z(17.95))
        .C(X(2.9), Z(18.0), X(3.1), Z(17.5), X(2.8), Z(17.25)), 0.36);
    線(p => p.M(X(4.8), Z(16.5)).C(X(4.9), Z(17.3), X(5.0), Z(18.0), X(5.1), Z(18.5)));
};
